import EventEmitter from"../event-emitter.js";describe("EventEmitter",()=>{test("on and emit",()=>{const e=new EventEmitter;var t=jest.fn();e.on("foo",t),e.emit("foo",42),expect(t).toHaveBeenCalledWith(42)}),test("once",()=>{const e=new EventEmitter;var t=jest.fn();e.once("bar",t),e.emit("bar"),e.emit("bar"),expect(t).toHaveBeenCalledTimes(1)}),test("unAll",()=>{const e=new EventEmitter;var t=jest.fn();e.on("foo",t),e.unAll(),e.emit("foo",1),expect(t).not.toHaveBeenCalled()})});